import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Pagination, StatusBadge, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { bhService } from '../../../services/bh/bhService';
import type { ContractDto } from '../../../services/bh/models';
import { formatDateLocal, formatVnd } from '../../../utils/format';
import styles from '../../../styles/erpPage.module.css';
const PAGE_SIZE = 20;
const HopDongListPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const [page, setPage] = useState(1);
  const [items, setItems] = useState<ContractDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  React.useEffect(() => {
    let c = false; setLoading(true);
    const t = setTimeout(() => {
      bhService.getContracts({ page, pageSize: PAGE_SIZE })
        .then(r => { if (!c) { setItems(r.items); setTotalCount(r.totalCount); } })
        .catch(e => { if (!c) dispatch(addToast({ message: e?.message ?? 'Lỗi', type: 'error' })); })
        .finally(() => { if (!c) setLoading(false); });
    }, 0);
    return () => { c = true; clearTimeout(t); };
  }, [page, dispatch]);
  return (
    <div className={styles.page}>
      <h1 className={styles.title}>Hợp đồng bán</h1>
      <div className={styles.tableCard}>
        {loading ? <div className={styles.loading}>...</div> : (
          <table className={styles.table}>
            <thead><tr><th>Số HĐ</th><th>Ngày</th><th>KH</th><th className={styles.colRight}>Giá trị</th><th>TT</th></tr></thead>
            <tbody>{items.map(r => (
              <tr key={r.id} onClick={() => navigate(`/bh/hd/${r.id}`)} style={{ cursor: 'pointer' }}>
                <td><code>{r.code}</code></td><td>{formatDateLocal(r.contractDate)}</td><td>{r.customerName}</td>
                <td className={styles.colRight}>{formatVnd(r.totalAmount)}</td><td><StatusBadge status={r.status} /></td>
              </tr>
            ))}</tbody>
          </table>
        )}
        {totalCount > 0 && <Pagination currentPage={page} totalPages={Math.ceil(totalCount/PAGE_SIZE)} totalCount={totalCount} pageSize={PAGE_SIZE} onPageChange={setPage} />}
      </div>
    </div>
  );
};
export default HopDongListPage;
